(21, 19, 5, 'MIC-INAL-001', 'Micrófono inalámbrico', 'Wireless Microphone', 'articulo_69833f1de4f2b.jpg', 25.00, NULL, 1, 0, 0, 'Incluye petaca transmisora, micrófono de mano y receptor. Requiere 2 pilas AA (no incluidas). Alcance hasta 100 metros en línea directa.', 'Includes bodypack transmitter, handheld microphone and receiver. Requires 2 AA batteries (not included). Range up to 100 meters in direct line.', 200, 'Verificar estado de baterías antes de cada alquiler. Comprobar frecuencias disponibles.', 1, 1, 0, 1, 1, '2025-11-20 20:33:47', '2026-02-13 16:33:55'),
(23, 22, NULL, 'MIX-DIG-X32', 'Consola digital Behringer X32', 'Behringer X32 Digital Console', 'articulos/consola_x32.jpg', 180.00, NULL, 0, 1, 0, 'Consola digital de 32 canales con 16 buses auxiliares, 8 efectos integrados y grabación multipista USB. Incluye flight case y cable de alimentación. Requiere corriente trifásica.', '32-channel digital console with 16 aux buses, 8 integrated effects and USB multitrack recording. Includes flight case and power cable. Requires three-phase power.', 200, 'Verificar configuración de escenas. Resetear a valores de fábrica después de cada uso.', 1, 1, 0, 1, NULL, '2025-11-20 20:33:47', '2026-01-20 17:35:38'),
(24, 21, 5, 'CABLE-XLR-10M', 'Cable XLR 10 metros', '10m XLR Cable', 'articulos/cable_xlr.jpg', 3.80, 0, 0, 0, 1, 'Cable balanceado XLR macho-hembra de 10 metros. Conductor OFC de baja impedancia.', '10m balanced XLR male-female cable. Low impedance OFC conductor.', 300, 'Verificar conectores y continuidad antes de alquilar.', 1, 0, 0, 1, 1, '2025-11-20 20:33:47', '2026-03-12 09:08:40'),
(25, 22, 5, 'LED-PANEL-P3', 'Pantalla LED modular P3 interior (por m²)', 'P3 Indoor LED Panel (per sqm)', 'articulo_6924b18b230b6.png', 450.00, 0, 0, 1, 0, 'Pantalla LED modular de pixel pitch 3mm para interior. Resolución 111.111 píxeles/m². Brillo 1200 nits. Incluye estructura de soporte, procesador de video y cableado. Requiere técnico especializado para montaje.', 'P3 indoor modular LED screen. Resolution 111,111 pixels/sqm. Brightness 1200 nits. Includes support structure, video processor and cabling. Requires specialized technician for assembly.', 50, 'Revisar píxeles muertos. Calibrar color antes de cada evento. Requiere montaje 24h antes.', 1, 1, 0, 1, NULL, '2025-11-20 20:33:47', '2025-11-24 19:27:07'),
